import os
from pathlib import Path
import pandas as pd

# Discover likely location of files first
candidates = [
    Path('/Documents/Financials'),
    Path('/workspace/Documents/Financials'),
    Path('/home/Documents/Financials'),
    Path('/root/Documents/Financials'),
    Path('/mnt/data/Documents/Financials'),
    Path('/mnt/Documents/Financials'),
]

found_dir = None
for d in candidates:
    if d.exists():
        if (d/'budget.xlsx').exists() and (d/'actual_spending.xlsx').exists():
            found_dir = d
            break

# Fallback search
if found_dir is None:
    for base in [Path('/workspace'), Path('/home'), Path('/root'), Path('/mnt'), Path('/')]:
        try:
            for p in base.rglob('budget.xlsx'):
                ap = p.parent / 'actual_spending.xlsx'
                if ap.exists():
                    found_dir = p.parent
                    break
            if found_dir is not None:
                break
        except Exception:
            pass

if found_dir is None:
    print('ERROR: Could not locate both budget.xlsx and actual_spending.xlsx')
    raise SystemExit(1)

budget_path = found_dir / 'budget.xlsx'
actual_path = found_dir / 'actual_spending.xlsx'
out_dir = Path('/workspace')
out_dir.mkdir(parents=True, exist_ok=True)

print('USING_DIR', found_dir)

budget = pd.read_excel(budget_path)
actual = pd.read_excel(actual_path)

rename_map_budget = {c:c.strip() for c in budget.columns if isinstance(c,str)}
rename_map_actual = {c:c.strip() for c in actual.columns if isinstance(c,str)}
budget = budget.rename(columns=rename_map_budget)
actual = actual.rename(columns=rename_map_actual)

for df in (budget, actual):
    for cand in ['Month','Period','Date','date','month','period']:
        if cand in df.columns:
            s = pd.to_datetime(df[cand], errors='coerce')
            if s.notna().any():
                df['YYYYMM'] = s.dt.strftime('%Y%m')
                break

budget.to_parquet(out_dir/'budget_normalized.parquet', index=False)
actual.to_parquet(out_dir/'actual_normalized.parquet', index=False)
print('WROTE', out_dir/'budget_normalized.parquet')
print('WROTE', out_dir/'actual_normalized.parquet')
